function solve(prices: number[], strategy: number[], k: number): number {
    const n = prices.length;
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + prices[i];
    }
    const val = strategy.map((s, i) => s * prices[i]);
    const original_profit = val.reduce((a, b) => a + b, 0);
    let windowSum = 0;
    for (let i = 0; i < k; i++) {
        windowSum += val[i];
    }
    let max_gain = 0;
    for (let i = 0; i <= n - k; i++) {
        const second_half_start = i + k / 2;
        const second_half_end = i + k - 1;
        const sum_second_half = prefixSum[second_half_end + 1] - prefixSum[second_half_start];
        const gain = sum_second_half - windowSum;
        if (gain > max_gain) {
            max_gain = gain;
        }
        if (i + k < n) {
            windowSum = windowSum - val[i] + val[i + k];
        }
    }
    return original_profit + Math.max(max_gain, 0);
}
```

